mapper.update:
update fulfillment_task
status = #{status}, completed_time = #{completedTime}, update_time = #{updateTime},
where order_id = #{orderId}

mapper.select:
select t.*, o.status as orderStatus, o.amount, o.phone, o.consignee, o.remark from fulfillment_task t left join orders o on t.order_id = o.id
and t.order_number = #{orderNumber} and o.phone like concat('%', #{phone}, '%') and t.status = #{status} and t.create_time >= #{beginTime} and t.create_time <= #{endTime}
order by t.create_time desc, t.id desc
